<?php
 namespace WPAICG\AutoGPT\Cron\Scheduler\Schedule; require_once __DIR__ . '/get-task-specific-cron-hook.php'; if (!defined('ABSPATH')) { exit; } function clear_task_event_logic(int $task_id): void { global $wpdb; $tasks_table_name = $wpdb->prefix . 'aipkit_automated_tasks'; $hook = get_task_specific_cron_hook_logic($task_id); $current_schedule_args = [$task_id]; wp_clear_scheduled_hook($hook, $current_schedule_args); $wpdb->update( $tasks_table_name, ['next_run_time' => null], ['id' => $task_id], ['%s'], ['%d'] ); } 